// Hand-authored (no "Generated by CLI Printing Press" header): preserved
// across regen. Adds a single-token persist path for StackAdapt's bearer
// auth model, which the generated OAuth-shaped SaveTokens does not cover.
package config

// SaveAPIToken persists tok as the StackAdapt API token (TOML key `api_token`),
// which is the field the GraphQL client reads via cfg.StackadaptApiToken.
//
// The generated SaveTokens stores into access_token and clears api_token, so
// `auth set-token` must use this method instead — otherwise the token lands in
// a field the client never reads and every API command fails with
// "no StackAdapt token" despite the credential being on disk. Any legacy
// auth_header is cleared so it can't shadow the freshly-saved token.
func (c *Config) SaveAPIToken(tok string) error {
	c.AuthHeaderVal = ""
	c.StackadaptApiToken = tok
	return c.save()
}
